import React, { useState } from 'react';

const App = () => {
  const [cart, setCart] = useState(false);
  const [price, setPrice] = useState(99.99);
  const handleAddToCart = () => {
    setCart(true);
    setTimeout(() => {
      setCart(false);
    }, 2000);
  };
  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white p-4 w-96 mx-auto rounded shadow">
        <div className="h-48 w-48 rounded mx-auto bg-cover" style={{ backgroundImage: 'url(https://via.placeholder.com/48)' }}></div>
        <div className="px-4">
          <h2>Product Name</h2>
          <div className="text-lg font-bold">$99.99</div>
        </div>
        <button className="bg-[#C06C88] hover:bg-[#B7D7CD] text-white font-bold py-2 px-4 rounded" onClick={handleAddToCart}>Add to Cart</button>
        {cart && <div className="bg-[#C06C88] p-4 text-white rounded mt-4">Product Added to Cart</div>}
      </div>
    </div>
  );
};

export default App;
